<template><div class="page-container"><PageHeader eyebrow="WORK LIBRARY" title="作品大厅" description="浏览、搜索并按分类筛选全部作品"/><div class="filter-panel"><el-input v-model="filters.keyword" clearable placeholder="输入作品名称" @keyup.enter="load"><template #prefix>⌕</template></el-input><el-select v-model="filters.status" clearable placeholder="作品状态"><el-option label="连载中" value="ONGOING"/><el-option label="已完结" value="COMPLETED"/><el-option label="即将上映" value="UPCOMING"/></el-select><el-select v-model="filters.categoryId" clearable placeholder="作品分类" @change="load"><el-option v-for="c in categories" :key="c.id" :label="c.name" :value="c.id"/></el-select><el-button type="primary" @click="load">搜索</el-button></div><div v-loading="loading" class="card-grid"><WorkCard v-for="item in page.list" :key="item.id" :work="item"/></div><EmptyState v-if="!loading&&!page.list.length" description="没有找到符合条件的作品"/><div class="pagination-wrap"><el-pagination background layout="prev, pager, next, total" :total="page.total" :page-size="filters.size" v-model:current-page="filters.current" @current-change="load"/></div></div></template>
<script setup>import { onMounted,reactive,ref } from 'vue';import { useRoute } from 'vue-router';import PageHeader from '../../components/PageHeader.vue';import WorkCard from '../../components/WorkCard.vue';import EmptyState from '../../components/EmptyState.vue';import { workApi } from '../../api/work';import { normalizePage } from '../../utils/page';const route=useRoute(),loading=ref(false),categories=ref([]),page=reactive({list:[],total:0}),filters=reactive({keyword:route.query.keyword||'',status:'',categoryId:'',current:1,size:12});async function load(){loading.value=true;try{let data;if(filters.categoryId)data=await workApi.categoryWorks(filters.categoryId,{current:filters.current,size:filters.size});else if(filters.keyword)data=await workApi.search({keyword:filters.keyword,current:filters.current,size:filters.size});else data=await workApi.page({current:filters.current,size:filters.size,status:filters.status||undefined});Object.assign(page,normalizePage(data))}finally{loading.value=false}}onMounted(async()=>{try{categories.value=await workApi.categories()}catch{};load()})</script>
